public int[] minOperations(String boxes) {
    int[] result = new int[boxes.length()];
    int count = 0, total = 0;

    for (int i = 0; i < boxes.length(); i++) {
        total += count;
        result[i] = total;
        if (boxes.charAt(i) == '1') count++;
    }

    count = 0;
    total = 0;
    for (int i = boxes.length() - 1; i >= 0; i--) {
        total += count;
        result[i] += total;
        if (boxes.charAt(i) == '1') count++;
    }

    return result;
}
